using System.ComponentModel.DataAnnotations;using System.ComponentModel.DataAnnotations.Schema;namespace CollegeManagementSystem.Data.Entities;[Table("Course")]public class Course{    [Key] public int Id { get; set; }    [Required] [MaxLength(50)] public string Name { get; set; } = string.Empty;    [Required] [MaxLength(10)] public int Duration { get; set; }}